```typescript
// Closure captures maxAttempts, baseDelayMs, jitter ‚Äî config is sealed at creation time
export function withRetry<T>(
  fn: () => Promise<T>,
  opts: { maxAttempts?: number; baseDelayMs?: number; jitter?: boolean } = {}
): () => Promise<T> {
  const { maxAttempts = 3, baseDelayMs = 100, jitter = true } = opts;
  return async function retried(): Promise<T> {
    for (let attempt = 1; attempt <= maxAttempts; attempt++) {
      try {
        return await fn();  // fn is closed over ‚Äî called fresh each attempt
      } catch (err) {
        if (attempt === maxAttempts) throw err;
        const delay = baseDelayMs * 2 ** (attempt - 1)
                    + (jitter ? Math.random() * baseDelayMs : 0);
        await sleep(delay);
      }
    }
    throw new Error('unreachable');
  };
}
```
