**Evening (2h):** Build `packages/utils/emitter.ts` ‚Äî `EventEmitter` from scratch, demonstrates prototypes and `this`:
```typescript
export class EventEmitter<Events extends Record<string, unknown[]>> {
  #listeners = new Map<keyof Events, Function[]>();
  on<K extends keyof Events>(event: K, listener: (...args: Events[K]) => void): this {
    if (!this.#listeners.has(event)) this.#listeners.set(event, []);
    this.#listeners.get(event)!.push(listener);
    return this;  // fluent API ‚Äî method chaining works because `this` is returned
  }
  once<K extends keyof Events>(event: K, listener: (...args: Events[K]) => void): this {
    const wrapper = (...args: Events[K]) => {
      listener.apply(this, args);  // explicit `this` ‚Äî wrapper closes over outer `this`
      this.off(event, wrapper);
    };
    return this.on(event, wrapper);
  }
  off<K extends keyof Events>(event: K, listener: Function): this {
    const arr = this.#listeners.get(event) ?? [];
    this.#listeners.set(event, arr.filter(l => l !== listener));
    return this;
  }
  emit<K extends keyof Events>(event: K, ...args: Events[K]): boolean {
    const listeners = this.#listeners.get(event) ?? [];
    listeners.forEach(l => l.apply(this, args));
    return listeners.length > 0;
  }
}
