```typescript
// 1. ConcurrencyLimiter ‚Äî max N concurrent async operations
export class ConcurrencyLimiter {
  #queue: Array<() => void> = [];
  #active = 0;
  constructor(private limit: number) {}
  async run<T>(fn: () => Promise<T>): Promise<T> {
    if (this.#active >= this.limit) {
      await new Promise<void>(resolve => this.#queue.push(resolve));
    }
    this.#active++;
    try {
      return await fn();
    } finally {
      this.#active--;
      this.#queue.shift()?.();  // wake next waiter
    }
  }
}
// 2. Implement Promise.all from scratch ‚Äî do not use the built-in
export function promiseAll<T>(promises: Promise<T>[]): Promise<T[]> {
  return new Promise((resolve, reject) => {
    const results: T[] = [];
    let remaining = promises.length;
    if (remaining === 0) { resolve(results); return; }
    promises.forEach((p, i) => {
      Promise.resolve(p).then(val => {
        results[i] = val;       // preserve order even if they settle out-of-order
        if (--remaining === 0) resolve(results);
      }, reject);
    });
  });
}
```
